import * as React from 'react';
import { useResizeObserver } from '@universe-design/react-utilities';
/**
 * @description
 * 用于检测某个元素是否出现了滚动条
 */
export function useScrollObserver<T extends HTMLElement = HTMLDivElement>() {
  const [scrolling, setScrolling] = React.useState(false);

  const isScrolling = React.useCallback((scrollElementRef: React.RefObject<T>) => {
    const element = scrollElementRef.current;
    if (!element) {
      return;
    }
    if (element.scrollTop > 0) {
      setScrolling(true);
    } else {
      setScrolling(false);
    }
  }, []);

  const scrollElementRef = useResizeObserver<T>(() => {
    isScrolling(scrollElementRef);
  });

  const handleScroll = React.useCallback(() => {
    isScrolling(scrollElementRef);
  }, [isScrolling, scrollElementRef]);

  React.useEffect(() => {
    const element = scrollElementRef.current;
    if (!element) {
      return;
    }

    element.addEventListener('scroll', handleScroll);
    return () => {
      element.removeEventListener('scroll', handleScroll);
    };
  }, [scrollElementRef, handleScroll]);

  return {
    scrolling,
    scrollElementRef,
  };
}
